"use client";

import { useEffect, useState } from "react";
import Image from "next/image";


type MenuItem = {
  _id?: string;
  name: string;
  description: string;
  price: number;
};

const categories = ["Food", "Drinks", "Brunch"];

export default function HomePage() {
  const [activeCategory, setActiveCategory] = useState("Food");
  const [items, setItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);

  // Fetch items whenever category changes
  useEffect(() => {
    async function fetchItems() {
      setLoading(true);
      try {
        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_BASE_URL}/menus/${activeCategory.toLowerCase()}`
        );
        const data = await res.json();
        setItems(data.items || []);
      } catch (err) {
        console.error(err);
        setItems([]);
      } finally {
        setLoading(false);
      }
    }

    fetchItems();
  }, [activeCategory]);

  return (
    <div className="w-full">
      
      {/* Hero Section with Overlay */}
      <section className="relative w-full h-[400px]">
        <Image
          src="/hero.jpg" 
          alt="Hero Background"
          fill
          className="object-cover"
        />
        <div className="absolute inset-0 bg-[#000000CC] flex flex-col items-center justify-center text-center text-white">
          <h2 className="text-[50px] font-oswald font-semibold tracking-[0.03em] uppercase">
            Menu
          </h2>
          <p className="mt-2 text-[18px]">Please take a look at our menu featuring food, drinks, and brunch. If you'd like to place an order, use the "Order Online" button located below the menu.</p>
        </div>
      </section>

      {/* Category Tabs */}
      <div className="bg-[#000000CC] text-white flex justify-center gap-8 py-4">
        {categories.map((cat) => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`uppercase font-oswald tracking-[0.03em] ${
              activeCategory === cat
                ? "border-b-2 border-yellow-400"
                : "hover:border-b-2 hover:border-gray-400"
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* Main Section with Background + Decorations */}
      <section className="relative w-full py-16">
        <Image
          src="/main-bg.jpg" // replace with exported background image
          alt="Main Background"
          fill
          className="object-cover -z-10"
        />

        {/* Side decorations */}
        <Image
          src="/decor-left.png"
          alt="Left Decoration"
          width={150}
          height={400}
          className="absolute left-0 top-20 hidden md:block"
        />
        <Image
          src="/decor-right.png"
          alt="Right Decoration"
          width={150}
          height={400}
          className="absolute right-0 top-20 hidden md:block"
        />

        <div className="max-w-4xl mx-auto px-6">
          <h3 className="text-[50px] font-oswald font-semibold uppercase tracking-[0.03em] text-center text-white mb-10">
            {activeCategory}
          </h3>

          {loading ? (
            <p className="text-center text-white">Loading...</p>
          ) : items.length === 0 ? (
            <p className="text-center text-white">No items found.</p>
          ) : (
            <ul className="space-y-6">
              {items.map((item) => (
                <li
                  key={item._id || item.name}
                  className="flex justify-between items-center text-white"
                >
                  <div>
                    <p className="font-oswald text-[26px] uppercase tracking-[0.03em]">
                      {item.name}
                    </p>
                    <p className="text-gray-300 text-sm">{item.description}</p>
                  </div>
                  <span className="font-oswald text-[26px] font-semibold tracking-[0.03em]">
                    ₹{item.price}
                  </span>
                </li>
              ))}
            </ul>
          )}
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-[#121618] text-white py-6 text-center text-sm">
        <p>© 2025 Deepnetsoft Solutions. All rights reserved.</p>
        <p className="mt-1">Contact: info@deepnetsoft.com</p>
      </footer>
    </div>
  );
}
